-- Patient distribution by conditionSELECT "Condition", COUNT(*) AS patient_countFROM hospital_data_analysisGROUP BY "Condition";-- Patient distribution by GenderSELECT "Gender", COUNT(*) AS total_patientsFROM hospital_data_analysisGROUP BY "Gender";-- Average Treatment Cost by ConditionSELECT "Condition", AVG("Cost") AS avg_costFROM hospital_data_analysisGROUP BY "Condition"ORDER BY avg_cost DESC;-- Average Length of StaySELECT "Condition", AVG("Length_of_Stay") AS avg_stayFROM hospital_data_analysisGROUP BY "Condition"ORDER BY avg_stay DESC;-- Patient Satisfaction AnalysisSELECT "Satisfaction", COUNT(*) AS totalFROM hospital_data_analysisGROUP BY "Satisfaction";-- Patient Outcome AnalysisSELECT "Outcome", COUNT(*) AS totalFROM hospital_data_analysisGROUP BY "Outcome";